INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0602235N$$, 2027, $$Activities and efforts in this program examine concepts and technologies that enable the transformation to Distributed Maritime Operations (DMO). Network centric
capabilities rely on information to connect assets and provide timely and accurate understanding of the environment. The mission area requirements for rapid,
accurate decision-making; dynamic, efficient, mission- focused communications and networks; and pervasive and persistent sensing drive network centric Science and
Technology (S&T) investments.

