$$, $$2f35839ef429567c7d6c4cc2f603d8e26c251b95d3a20b8eb440426a3e5adcda$$, $${"A": "52649a512ca78ccaffbf5792ef92462b926390b4ec72b4254d76eb428861337f", "C": "d4fdf923ba776b98bda680220afe7660b2fb7f78e25f4cb026ad0b29031d9620", "D": "2c5c5104d84fd9d59299ec10bcd6c760ce15de1514c4f2a57382766b58f0a66d"}$$::jsonb, $$Budget J-Books/FY26/Navy/RDTEN_BA4_Book.pdf$$, 239, $$2026-05-10T04:03:06.372628+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0603506N$$, 2026, $$The Surface Ship Torpedo Defense (SSTD) program provides a detect-to-engage layered torpedo defense capability. The four (4) major efforts that comprise SSTD are
the AN/SLQ-25 (NIXIE) system, Torpedo Warning System (TWS), the Countermeasure Anti-Torpedo (CAT), and Acoustic Device Countermeasure (Surface ADC MK2).
A layered torpedo defense to protect surface ships against current and future threats. SSTD development will include a new anti-torpedo Hard Kill (HK) capability by
pairing proven technology and the MK 58 Compact Rapid Attack Weapon (CRAW) with improved AN/SLQ-25E that has additional software capabilities. An upgrade to
the AN/SLQ25E system using MK 58 CRAW along with an ADC launcher is detailed below as the NIXIE HK.

 FY 2024 funding provided minimal support to the 2 remaining CVN installations with system preservation the primary focus. FY 2024 funding also supported the
 beginning of a Research, Development, Test & Evaluation (RDT&E) planning efforts to develop and incorporate TWS capabilities into the AN/SLQ-25 (Nixie) via a series
 Tech Insertions (TIs). FY 2025 funding supported the two remaining TWS on installed systems and established development of a NIXIE follow-on Torpedo Defense
 Hardkill System that will incorporate the capabilities of the TWS, the Compact Rapid Attack Weapon (CRAW), and ADC MK2 MOD6/8. FY 2026 funding will support the
 continued development of the NIXIE Torpedo Defense Hardkill (HK) system with concentration on the development of the torpedo alertment and fire control / Torpedo
 Warning System (TWS) integration into the NIXIE 25E tow. FY 2026 funds will also support the development of NIXIE 25E software & winch improvements along with
 the development of a CRAW launcher that will be capable of launching the Anti-Torpedo Torpedo (ATT) variant of the CRAW and the ADC MK2 MOD 6/8 and MK5
 (series) Acoustic Countermeasures Device (ADC).

 Research and development of new technologies and capabilities for torpedo defense initiated under the Future Naval Capabilities (FNC), Small Business and Innovative
 Research (SBIR), and/or other Research, Development, Test & Evaluation (RDT&E) initiatives are evaluated to determine their effectiveness and impact on improving
 ship survivability. Evaluations of new and emerging torpedo defense hardware and software in representative acoustic environments, against projected threats using
 both digital and hardware-in-the-loop simulations will be performed. The potential hardware and software will be considered for integration into the modular and
 Commercial-Off-The-Shelf (COTS)-based design of AN/SLQ-25E, which allows for future capability growth into a NIXIE HK System to outpace the threat in torpedo
 defense.
Component Development & Prototypes (ACD&P)$$, $$ATTDS is a system of systems, comprised of the Torpedo Warning System (TWS) and the Countermeasure Anti-Torpedo Torpedo planned to develop NIXIE HK new
AN/SLQ-25 capabilities in order to pace the torpedo threat. This includes integrating and testing a kinematics-based target discrimination and fire control into the AN/
SLQ-25E, improving existing soft kill capabilities within AN/SLQ-25E, and adding a hard kill capability with a launcher for the Mk 58 CRAW and the (ADC) MK5 and MK
2 Mod 6/8. The FY 2026 funds support the development of a torpedo alertment and fire control capability integrated into the AN/SLQ-25E tow system in support of a
torpedo defense requirements along with software improvements to specific NIXIE counter measures.

